String hmacSha256(String secret, String data) {
  final keyBytes = utf8.encode(secret);
  final messageBytes = utf8.encode(data);
  final digest = Hmac(
    macAlgorithm: MacAlgorithm.HMAC_SHA_256,
    key: keyBytes,
  ).generate(messageBytes);
  return base64Encode(digest);
}